&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;President Smt. Droupadi Murmu inaugurated the four-day National Arogya Fair 2026 at Shegaon in the Buldhana district of Maharashtra.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The National Arogya Fair 2026 was organized by the Ministry of Ayush in collaboration with the All India Ayurvedic Congress from 25th to 28th February 2026 at Shegaon, Buldhana.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;The event focuses on integrating healthcare outreach with the enhancement of farmers&amp;#39; income through the cultivation and marketing of medicinal plants.&lt;/li&gt;
	&lt;li&gt;It provides a public platform for free consultations and health check-ups across the Ayush systems: Ayurveda, Yoga &amp;amp; Naturopathy, Unani, Siddha, Sowa-Rigpa, and Homoeopathy.&lt;/li&gt;
	&lt;li&gt;A specialized session titled &amp;#39;Ayurvedic Farming: Production, Value Addition and Marketing&amp;#39; was designed specifically for the farmers of the Vidarbha region.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0); &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Ayush Systems&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Ayurveda, Yoga &amp;amp; Naturopathy, Unani, Siddha, Sowa-Rigpa, and Homoeopathy form the core traditional healthcare systems promoted by the Ministry.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Sowa-Rigpa&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;One of the oldest medical traditions, widely practiced in the Himalayan regions like Ladakh, Himachal Pradesh, and Sikkim.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Shegaon&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Located in Buldhana district, it is a famous pilgrimage site known for the Samadhi of Sant Gajanan Maharaj.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Medicinal Plants Board (NMPB)&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Established - 2000&lt;/li&gt;
		&lt;li&gt;Function - Nodal agency under the Ministry of Ayush to coordinate all matters related to medicinal plants in India.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;
